/**
 * @param {number} n
 * @param {number} m
 * @param {number[][]} sources
 * @return {number[][]}
 */
function solve(n, m, sources) {
    // The problem describes a multi-source shortest path problem where the "cost"
    // is the time taken to reach a cell, and if multiple colors reach at the same
    // time, the one with the maximum color value wins.
    // This is equivalent to a 0-1 BFS or Dijkstra's algorithm where we prioritize
    // by time (distance) and then by color (for tie-breaking).

    // Since all edge weights (time increments) are 1, a standard Breadth-First Search (BFS)
    // approach, extended for multiple sources and custom tie-breaking, is appropriate.

    // dist[r][c] will store the minimum time required to reach (r, c).
    // Initialize with Infinity.
    const dist = Array(n).fill(0).map(() => Array(m).fill(Infinity));

    // colorGrid[r][c] will store the final color of (r, c).
    // Initialize with 0 (uncolored).
    const colorGrid = Array(n).fill(0).map(() => Array(m).fill(0));

    // Priority Queue stores [time, -color, r, c].
    // We use -color because JS standard queues are FIFO, but Dijkstra/BFS requires
    // prioritizing shorter times. When times are equal, we prioritize higher colors.
    // Since we are simulating a time-based expansion, a standard queue might be sufficient
    // if we process layers sequentially (like a level-by-level BFS).

    // A Min-Heap based on (time, -color) is the robust approach here, as it handles
    // the dynamic nature of the arrival time and color preference.

    // We'll use a simple array simulation of a Min-Priority Queue, sorting it when needed,
    // or implement a proper MinHeap if performance becomes an issue, but given N*M <= 10^5,
    // a heap implementation is standard for Dijkstra's.

    // Let's use a simple array simulating a priority queue (or deque/queue if we analyze the structure).
    // Since all expansion times are +1, a standard BFS queue (FIFO) works for time,
    // but the color update rule is complex: "If multiple colors arrive at the same time step,
    // the cell adopts the maximum color."

    // We can use a structure similar to Multi-Source BFS:
    // Queue stores [r, c, time, color].

    // However, if we only track the arrival time in `dist`, we need a way to track
    // which color is the best one that achieved that minimum time.

    // Let's use Dijkstra's where the state in the PQ is [time, -color, r, c].
    // The distance metric must capture both time and color preference for relaxation.

    // PQ stores [time, negative_color, r, c]
    const pq = [];

    for (const [r, c, color] of sources) {
        dist[r][c] = 0;
        colorGrid[r][c] = color;
        // Push [time, -color, r, c]
        // Negative color ensures that when time is equal, the largest color has the smallest value in the heap.
        pq.push([0, -color, r, c]);
    }

    // Simple Heap Implementation (Min-Heap based on [time, -color])
    // We'll use an array and simulate heap operations for simplicity/completeness in a single block,
    // assuming N*M is small enough for JS overheads not to strictly mandate a complex heap implementation.
    // Since JS doesn't have a built-in Heap, we must implement one or use a sorted array/queue approach.
    // Given the constraints, a proper heap is necessary for O(E log V).

    // Standard library approach in competitive programming environments often allows helper classes.
    class MinPriorityQueue {
        constructor() {
            this.heap = [];
        }

        isEmpty() {
            return this.heap.length === 0;
        }

        _getParentIndex(i) { return Math.floor((i - 1) / 2); }
        _getLeftChildIndex(i) { return 2 * i + 1; }
        _getRightChildIndex(i) { return 2 * i + 2; }

        _swap(i, j) {
            [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
        }

        // Comparison function: Compares [time, neg_color, r, c]
        // Returns true if item A has higher priority (smaller value) than item B.
        _compare(a, b) {
            if (a[0] !== b[0]) {
                return a[0] < b[0]; // Lower time wins
            }
            return a[1] < b[1]; // Smaller -color (i.e., larger color) wins
        }

        enqueue(element) {
            this.heap.push(element);
            this._bubbleUp(this.heap.length - 1);
        }

        dequeue() {
            if (this.isEmpty()) return null;
            if (this.heap.length === 1) return this.heap.pop();

            const root = this.heap[0];
            this.heap[0] = this.heap.pop();
            this._bubbleDown(0);
            return root;
        }

        _bubbleUp(index) {
            let currentIndex = index;
            let parentIndex = this._getParentIndex(currentIndex);

            while (currentIndex > 0 && this._compare(this.heap[currentIndex], this.heap[parentIndex])) {
                this._swap(currentIndex, parentIndex);
                currentIndex = parentIndex;
                parentIndex = this._getParentIndex(currentIndex);
            }
        }

        _bubbleDown(index) {
            let currentIndex = index;
            const lastIndex = this.heap.length - 1;

            while (true) {
                let left = this._getLeftChildIndex(currentIndex);
                let right = this._getRightChildIndex(currentIndex);
                let smallest = currentIndex;

                // Check left child
                if (left <= lastIndex && this._compare(this.heap[left], this.heap[smallest])) {
                    smallest = left;
                }

                // Check right child
                if (right <= lastIndex && this._compare(this.heap[right], this.heap[smallest])) {
                    smallest = right;
                }

                if (smallest !== currentIndex) {
                    this._swap(currentIndex, smallest);
                    currentIndex = smallest;
                } else {
                    break;
                }
            }
        }
    }

    const minHeap = new MinPriorityQueue();

    for (const [r, c, color] of sources) {
        dist[r][c] = 0;
        colorGrid[r][c] = color;
        minHeap.enqueue([0, -color, r, c]);
    }

    const dr = [-1, 1, 0, 0];
    const dc = [0, 0, -1, 1];

    while (!minHeap.isEmpty()) {
        const [d, negColor, r, c] = minHeap.dequeue();
        const color = -negColor;

        // Crucial check: If we found a better way to reach (r, c) since this entry was queued, skip.
        // The "better" way means a strictly smaller time, OR the same time but a strictly larger color.
        // Since Dijkstra's ensures we process the best path first, if the current stored distance/color
        // is strictly better than what this PQ entry represents, we skip.
        // A simpler check is sufficient if the relaxation logic is correct:
        if (d > dist[r][c] || (d === dist[r][c] && color < colorGrid[r][c])) {
            continue;
        }


        for (let i = 0; i < 4; i++) {
            const nr = r + dr[i];
            const nc = c + dc[i];

            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {
                const newTime = d + 1;
                const newColor = color;

                // Relaxation Condition:
                // 1. If the neighbor is uncolored (or reached with higher time), we might update.
                // 2. If the neighbor has been reached, we check if this new path is better.

                const currentTime = dist[nr][nc];
                const currentColor = colorGrid[nr][nc];

                let shouldUpdate = false;

                if (currentTime === Infinity) {
                    // Uncolored cell: Always update if we reach it
                    shouldUpdate = true;
                } else if (newTime < currentTime) {
                    // Faster arrival: Always update
                    shouldUpdate = true;
                } else if (newTime === currentTime) {
                    // Same time arrival: Update if the new color is larger
                    if (newColor > currentColor) {
                        shouldUpdate = true;
                    }
                }

                if (shouldUpdate) {
                    dist[nr][nc] = newTime;
                    colorGrid[nr][nc] = newColor;
                    // Push the new state into the PQ
                    minHeap.enqueue([newTime, -newColor, nr, nc]);
                }
            }
        }
    }

    return colorGrid;
}

