fn solve(n: i64, m: i64, sources: Vec<Vec<i64>>) -> Vec<Vec<i64>> {
    use std::collections::BinaryHeap;
    use std::cmp::Reverse;

    // State stored in the priority queue: (time, -color, r, c)
    // We use BinaryHeap which is a Max-Heap. To simulate a Min-Heap based on time,
    // and then Max-Heap based on color (i.e., Min-Heap based on -color),
    // we define the tuple comparison carefully.
    // Since Rust's tuple comparison is lexicographical, we want:
    // 1. Smallest time comes first (use `Reverse` on time)
    // 2. Largest color comes first (use the color directly, as a larger positive color
    //    will be larger in a Max-Heap, but we want the *smallest* negative color)
    //
    // Let's store (-time, color, r, c) to use a standard Max-Heap structure:
    // - The largest negative time (closest to zero, smallest time) comes first.
    // - If times are equal, the largest color comes first.

    #[derive(Eq, PartialEq, Clone, Copy)]
    struct State {
        neg_time: i64, // Negative time to simulate min-heap on time
        color: i64,
        r: i64,
        c: i64,
    }

    // Implement Ord for Max-Heap behavior: higher priority state comes first.
    impl Ord for State {
        fn cmp(&self, other: &Self) -> std::cmp::Ordering {
            // 1. Prioritize smaller time (i.e., larger neg_time)
            match self.neg_time.cmp(&other.neg_time) {
                std::cmp::Ordering::Equal => {
                    // 2. If times are equal, prioritize larger color
                    self.color.cmp(&other.color)
                }
                other => other, // Standard comparison on neg_time
            }
        }
    }

    impl PartialOrd for State {
        fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
            Some(self.cmp(other))
        }
    }

    let n_usize = n as usize;
    let m_usize = m as usize;

    // Initialize distance (time) grid to infinity
    let infinity = i64::MAX;
    let mut dist: Vec<Vec<i64>> = vec![vec![infinity; m_usize]; n_usize];

    // Initialize color grid to 0 (uncolored)
    let mut color_grid: Vec<Vec<i64>> = vec![vec![0; m_usize]; n_usize];

    // Min-Priority Queue simulation using BinaryHeap (Max-Heap structure)
    let mut pq: BinaryHeap<State> = BinaryHeap::new();

    for source in sources {
        let r = source[0] as usize;
        let c = source[1] as usize;
        let color = source[2];

        dist[r][c] = 0;
        color_grid[r][c] = color;
        pq.push(State {
            neg_time: 0, // Time is 0
            color,
            r: r as i64,
            c: c as i64,
        });
    }

    let dr = [-1, 1, 0, 0];
    let dc = [0, 0, -1, 1];

    while let Some(State { neg_time: d_neg, color, r: r_i64, c: c_i64 }) = pq.pop() {
        let d = -d_neg;
        let r = r_i64 as usize;
        let c = c_i64 as usize;

        // Optimization: Check if this entry is stale.
        // If we found a better path (smaller time, or same time but larger color)
        // since this was enqueued, skip it.
        if d > dist[r][c] || (d == dist[r][c] && color < color_grid[r][c]) {
            continue;
        }


        for i in 0..4 {
            let nr_i64 = r_i64 + dr[i];
            let nc_i64 = c_i64 + dc[i];

            if nr_i64 >= 0 && nr_i64 < n && nc_i64 >= 0 && nc_i64 < m {
                let nr = nr_i64 as usize;
                let nc = nc_i64 as usize;

                let new_time = d + 1;
                let new_color = color;

                let current_time = dist[nr][nc];
                let current_color = color_grid[nr][nc];

                let mut should_update = false;

                if current_time == infinity {
                    // Uncolored cell: Always update if reachable
                    should_update = true;
                } else if new_time < current_time {
                    // Faster arrival: Always update
                    should_update = true;
                } else if new_time == current_time {
                    // Same time arrival: Update if the new color is larger
                    if new_color > current_color {
                        should_update = true;
                    }
                }

                if should_update {
                    dist[nr][nc] = new_time;
                    color_grid[nr][nc] = new_color;

                    pq.push(State {
                        neg_time: -(new_time),
                        color: new_color,
                        r: nr_i64,
                        c: nc_i64,
                    });
                }
            }
        }
    }

    color_grid
}
