use std::collections::BinaryHeap;
use std::cmp::Ordering;

// Define a struct for the state in the priority queue
// We want a MIN-HEAP based on (time, -color).
// Rust's BinaryHeap is a MAX-HEAP, so we must implement Ord such that the desired smallest element
// has the largest 'Ord' value when comparing for the max-heap behavior to simulate min-heap.
#[derive(Eq, PartialEq, Clone, Copy)]
struct State {
    time: i64,
    // Use negative color representation for comparison purposes in a max-heap to simulate min-heap on color
    // A larger color should result in a smaller effective value (higher priority).
    // Since we are maximizing color, we negate it.
    neg_color: i64, 
    r: i64,
    c: i64,
}

impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        // Priority 1: Minimize time (Lower time means higher priority)
        // If self.time < other.time, self should be prioritized (should be "greater" in max-heap terms)
        match other.time.cmp(&self.time) {
            Ordering::Equal => {
                // Priority 2: Maximize color (Larger color means higher priority)
                // If self.neg_color < other.neg_color (meaning self.color > other.color), 
                // self should be prioritized (should be "greater" in max-heap terms)
                self.neg_color.cmp(&other.neg_color)
            },
            other_ordering => other_ordering,
        }
    }
}

impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}


