    // Since JS doesn't have a built-in Heap, we must implement one or use a sorted array/queue approach.
    // Given the constraints, a proper heap is necessary for O(E log V).

    // Standard library approach in competitive programming environments often allows helper classes.
    class MinPriorityQueue {
        constructor() {
            this.heap = [];
        }

        isEmpty() {
            return this.heap.length === 0;
        }

        _getParentIndex(i) { return Math.floor((i - 1) / 2); }
        _getLeftChildIndex(i) { return 2 * i + 1; }
        _getRightChildIndex(i) { return 2 * i + 2; }

